<template>
    <div class="panel panel-default">
      <div class="panel-heading">
        主页
      </div>
      <div class="panel-body">
        <div style="margin: 10px;">
          <!--文章列表循环输出-->
          <div class="media" style="border-top: 1px solid #ccc" v-for="(item,index) in articles" :key="index">
            <div style="margin-top: 5px">
              <div class="media-left">
                <img :src="item.thumb" class="media-object" style="width:60px">
              </div>
              <div class="media-body">
                <h4 class="media-heading" style="overflow: hidden;height: 18px"><router-link style="text-decoration: none" :to="'../'+item.path">{{item.title}}</router-link></h4>
                <p style="overflow: hidden;height: 20px">{{item.summary}}</p>
                <div>
                  <span style="color: #969799">发布日期：{{item.created_at}}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
</template>

<script>
import axios from 'axios';
import BScroll from 'better-scroll';
    export default {
        name: "home",
        data(){
          return{
            page:0,
            articles:[]
          }
        },
        watch:{
          articles(){
            this.$nextTick(() => {
              // 让当前的页码+1
              this.page += 1;
              // 初始化
              this.touch_end();
            })
          }
        },
        created(){
          axios.get(this.$store.state.domain+'test3',{
            params:{
              page:this.page
            }
          }).then((res)=>{
            this.articles = res.data.concat(this.articles)
          })
        },
        mounted(){
          this.touch_end()
        },
        methods:{
          touch_end(){
            var that = this;
            window.onscroll = function () {
              var scrollTop = $(this).scrollTop();
              var scrollHeight = $(document).height();
              var windowHeight = document.body.clientHeight;
              if (scrollTop+windowHeight == scrollHeight){
                    axios.get(that.$store.state.domain+'test3',{
                      params:{
                        page:that.page
                      }
                    }).then((res)=>{
                      if (res.data == ''){
                        return;
                      }else{
                        that.articles = that.articles.concat(res.data)
                      }
                    })
              }
            }

            // $(window).scroll(function(){
            //
            //   var scrollTop = $(this).scrollTop();
            //   var scrollHeight = $(document).height();
            //   var windowHeight = $(this).height();
            //   if(scrollTop + windowHeight >= scrollHeight-1){
            //
            //       console.log('scrollTop:'+scrollTop)
            //       console.log('scrollHeight:'+scrollHeight)
            //       console.log('windowHeight:'+windowHeight)
            //     // axios.get('https://wx.xinyangwei.cn/test3',{
            //     //   params:{
            //     //     page:that.page
            //     //   }
            //     // }).then((res)=>{
            //     //   that.articles = res.data.concat(that.articles)
            //     // })
            //
            //   }
            // });
          },


        }
    }
</script>

<style scoped lang="stylus" ref="stylesheet/stylus">

</style>



