<template>

  <div class="panel panel-default" v-if="article == 'no'">
    <div class="panel-heading" style="text-align: center;font-size: 22px">
      没有相关文章
    </div>
    <div class="panel-body">

      <div class="content">

      </div>
    </div>
  </div>

  <div class="panel panel-default" v-else>
    <div class="panel-heading" style="text-align: center;font-size: 22px">
      {{article.title}}
    </div>
    <div class="panel-body">
      <div class="article-introduce"><span>作者：{{article.author}}</span><span style="margin-left: 20px">发布时间：{{article.created_at}}</span><span style="margin-left: 20px">tags:{{article.tags}}</span></div>
      <div class="content">
        {{article.content}}
      </div>
    </div>
  </div>


</template>

<script>
  import axios from 'axios'
    export default {
        name: "articles",
        data(){
          return{
            article:[]
          }
        },
        created(){
          axios.get(this.$store.state.domain+this.$route.path,{}).then((res)=>{
            console.log(res);
            this.article =  res.data
          })
        }
    }
</script>

<style lang="stylus" ref="stylesheet/stylus" scoped>
    .article-introduce
      text-align center
      span
        color #969799
    .content
      margin-top 20px
</style>



